import React from 'react';
// import { useRouteMatch } from 'react-router-dom';
import PropTypes from 'prop-types';

import './ArticlesPage.scss';

export const ArticlesPage = ({ article }) => {
  // const match = useRouteMatch();
  // console.log(match);
  const value = {
    title: 'Covid survivors still at reinfection risk from Alpha, Beta variants',
    description: 'Immune response following a coronavirus infection can vary between individuals and may not be enough to fight Alpha, and Beta variant of Covid-19, finds a study reinforcing the need for vaccination.',
    content: 'Follow us on Image Source : AP Covid survivors still at reinfection risk from Alpha, Beta variants (Representational Image)\nImmune response following a coronavirus infection can vary between individuals and may not be enough to fight Alpha, and Beta ... [2547 chars]',
    url: 'https://www.indiatvnews.com/news/world/covid-survivors-still-at-reinfection-risk-from-alpha-beta-variants-713343',
    image: 'https://resize.indiatvnews.com/en/resize/newbucket/715_-/2021/06/us-virus-variant-1624207087.jpeg',
    publishedAt: '2021-06-20T16:38:37Z',
    source: {
      name: 'India TV News',
      url: 'https://www.indiatvnews.com',
    },
  };

  return (
    <div className="ArticlesPage">
      <div className="ArticlesPage-Article Article">
        <div className="Article-Image">
          <img
            className="image-article"
            src={value.image}
            width="1700"
            height="380"
            alt="Foto"
          />
        </div>
        <div className="Article-Content">
          <h1 className="Article-Title">
            {value.title}
          </h1>
          <div className="Article-Info">
            <p className="Article-Author">{`Source "${value.source.name}"`}</p>
            <p className="Article-Date">{new Date(value.publishedAt.slice(0, 10)).toString().slice(4, 15)}</p>
          </div>
          {/* <br className="decor" /> */}
          <div className="Article-Summary">
            {/* {value.description} */}
            {value.content}
            {/* Section 1.10.32 of "de Finibus Bonorum et Malorum", written by Cicero in 45 BC "Sed ut perspiciatis unde omnis iste natus error sit voluptatem accusantium doloremque laudantium, totam rem aperiam, eaque ipsa quae ab illo inventore veritatis et quasi architecto beatae vitae dicta sunt explicabo. Nemo enim ipsam voluptatem quia voluptas sit aspernatur aut odit aut fugit, sed quia consequuntur magni dolores eos qui ratione voluptatem sequi nesciunt. Neque porro quisquam est, qui dolorem ipsum quia dolor sit amet, consectetur, adipisci velit, sed quia non numquam eius modi tempora incidunt ut labore et dolore magnam aliquam quaerat voluptatem. Ut enim ad minima veniam, quis nostrum exercitationem ullam corporis suscipit laboriosam, nisi ut aliquid ex ea commodi consequatur? Quis autem vel eum iure reprehenderit qui in ea voluptate velit esse quam nihil molestiae consequatur, vel illum qui dolorem eum fugiat quo voluptas nulla pariatur?" */}
          </div>
        </div>
      </div>
    </div>
  );
};

ArticlesPage.propTypes = {
  article: PropTypes.shape({
    title: PropTypes.string.isRequired,
    content: PropTypes.string.isRequired,
    image: PropTypes.string.isRequired,
    source: PropTypes.shape({
      name: PropTypes.string.isRequired}).isRequired,
    publishedAt: PropTypes.string.isRequired,
  }).isRequired,
};
